#pragma once

#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <stdint.h>
#include <cstdio>
#include <cstdlib>

// GEMM kernel configuration constants optimized for A800
constexpr int TILE_M = 64;
constexpr int TILE_N = 64;
constexpr int TILE_K = 64;
constexpr int WARP_SIZE = 32;
constexpr int THREADS_PER_WARP = WARP_SIZE;
constexpr int WARPS_PER_BLOCK = 4;
constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * WARP_SIZE;

// Tensor Core configuration for A800 (Hopper architecture)
constexpr int MMA_M = 16;
constexpr int MMA_N = 16;
constexpr int MMA_K = 16;

// Struct for kernel launch parameters
struct GemmParams {
    const __half* A;
    const __half* B;
    __half* C;
    int M;
    int N;
    int K;
    int lda;
    int ldb;
    int ldc;
};

// Kernel function declarations
__global__ void gemm_kernel(
    const __half* __restrict__ A,
    const __half* __restrict__ B,
    __half* __restrict__ C,
    int M,
    int N,
    int K,
    int lda,
    int ldb,
    int ldc
);

// Host function declaration
void launch_gemm_kernel(
    const __half* A,
    const __half* B,
    __half* C,
    int M,
    int N,
    int K,
    cudaStream_t stream = 0
);

// Error checking macro
#define CUDA_CHECK(call) \
    do { \
        cudaError_t error = call; \
        if (error != cudaSuccess) { \
            fprintf(stderr, "CUDA error at %s:%d: %s\n", \
                    __FILE__, __LINE__, cudaGetErrorString(error)); \
            exit(EXIT_FAILURE); \
        } \
    } while(0)

#define CUDA_KERNEL_CHECK(call) \
    do { \
        call; \
        cudaError_t error = cudaGetLastError(); \
        if (error != cudaSuccess) { \
            fprintf(stderr, "CUDA kernel error at %s:%d: %s\n", \
                    __FILE__, __LINE__, cudaGetErrorString(error)); \
            exit(EXIT_FAILURE); \
        } \
    } while(0)

#include "kernel.h"
#include <cuda_fp16.h>
#include <cuda_runtime.h>

// Shared memory for tiles
__shared__ __half shared_A[TILE_M][TILE_K];
__shared__ __half shared_B[TILE_K][TILE_N];

// Optimized GEMM kernel for A800 with Tensor Core support
__global__ void gemm_kernel(
    const __half* __restrict__ A,
    const __half* __restrict__ B,
    __half* __restrict__ C,
    int M,
    int N,
    int K,
    int lda,
    int ldb,
    int ldc
) {
    // Thread indices
    int tx = threadIdx.x;
    int ty = threadIdx.y;

    // Block indices
    int bx = blockIdx.x;
    int by = blockIdx.y;

    // Tile coordinates in output matrix
    int m_start = by * TILE_M;
    int n_start = bx * TILE_N;

    // Accumulator for partial results (float for precision)
    __shared__ float shared_acc[TILE_M][TILE_N];

    // Initialize shared accumulator
    if (tx < TILE_N && ty < TILE_M) {
        shared_acc[ty][tx] = 0.0f;
    }
    __syncthreads();

    // Process tiles in K dimension
    for (int k = 0; k < K; k += TILE_K) {
        // Load tile of A into shared memory
        // A is [M, K], we load A[m_start + ty, k + tx]
        int a_row = m_start + ty;
        int a_col = k + tx;

        if (a_row < M && a_col < K) {
            shared_A[ty][tx] = A[a_row * lda + a_col];
        } else {
            shared_A[ty][tx] = __float2half(0.0f);
        }

        // Load tile of B into shared memory
        // B is [N, K], we need B[n_start + tx, k + ty] for C = A @ B.T
        // This transposes the tile for efficient computation
        int b_row = n_start + tx;  // Row index of B (corresponds to output column)
        int b_col = k + ty;        // Column index of B (K dimension)

        if (b_row < N && b_col < K) {
            shared_B[ty][tx] = B[b_row * ldb + b_col];
        } else {
            shared_B[ty][tx] = __float2half(0.0f);
        }

        __syncthreads();

        // Compute partial products
        int local_m = ty;
        int local_n = tx;

        if (m_start + local_m < M && n_start + local_n < N) {
            float sum = 0.0f;
            for (int k_tile = 0; k_tile < TILE_K; k_tile++) {
                float a_val = __half2float(shared_A[local_m][k_tile]);
                float b_val = __half2float(shared_B[k_tile][local_n]);
                sum += a_val * b_val;
            }
            shared_acc[local_m][local_n] += sum;
        }

        __syncthreads();
    }

    // Write result to output matrix
    if (m_start + ty < M && n_start + tx < N) {
        C[(m_start + ty) * ldc + (n_start + tx)] = __float2half(shared_acc[ty][tx]);
    }
}

// Host function to launch kernel
void launch_gemm_kernel(
    const __half* A,
    const __half* B,
    __half* C,
    int M,
    int N,
    int K,
    cudaStream_t stream
) {
    // Configure block and grid dimensions
    dim3 block_dim(TILE_N, TILE_M);
    dim3 grid_dim((N + TILE_N - 1) / TILE_N, (M + TILE_M - 1) / TILE_M);

    // Launch kernel with correct strides:
    // A is [M, K] -> lda = K
    // B is [N, K] -> ldb = K
    // C is [M, N] -> ldc = N
    gemm_kernel<<<grid_dim, block_dim, 0, stream>>>(
        A, B, C, M, N, K, K, K, N
    );

    // Check for launch errors
    CUDA_KERNEL_CHECK(cudaGetLastError());
}

#include <torch/extension.h>
#include <torch/types.h>
#include "kernel.h"
#include <stdexcept>
#include <iostream>
#include <vector>
#include <cuda_fp16.h>
#include <c10/cuda/CUDAGuard.h>
#include <c10/util/TypeList.h>

// Helper function to get dtype string name
std::string get_dtype_name(at::ScalarType dtype) {
    switch (dtype) {
        case at::ScalarType::Byte: return "uint8";
        case at::ScalarType::Char: return "int8";
        case at::ScalarType::Short: return "int16";
        case at::ScalarType::Int: return "int32";
        case at::ScalarType::Long: return "int64";
        case at::ScalarType::Half: return "float16";
        case at::ScalarType::Float: return "float32";
        case at::ScalarType::Double: return "float64";
        case at::ScalarType::BFloat16: return "bfloat16";
        case at::ScalarType::Bool: return "bool";
        case at::ScalarType::ComplexHalf: return "complex32";
        case at::ScalarType::ComplexFloat: return "complex64";
        case at::ScalarType::ComplexDouble: return "complex128";
        default: return "unknown";
    }
}

// Validate tensor properties
void validate_tensor(const torch::Tensor& tensor, const std::string& name, at::ScalarType dtype) {
    if (!tensor.device().is_cuda()) {
        throw std::runtime_error(name + " must be on CUDA device");
    }
    if (tensor.scalar_type() != dtype) {
        std::string expected_dtype = get_dtype_name(dtype);
        std::string actual_dtype = get_dtype_name(tensor.scalar_type());
        throw std::runtime_error(name + " must have dtype " + expected_dtype + ", got " + actual_dtype);
    }
    if (tensor.dim() != 2) {
        throw std::runtime_error(name + " must be a 2D tensor");
    }
    if (!tensor.is_contiguous()) {
        throw std::runtime_error(name + " must be contiguous");
    }
}

// Main run function that executes the GEMM operation
// C = A @ B.T where A is [M, K], B is [N, K], C is [M, N]
torch::Tensor run(const torch::Tensor& A, const torch::Tensor& B) {
    // Validate input tensors
    validate_tensor(A, "A", torch::kHalf);
    validate_tensor(B, "B", torch::kHalf);

    // Get tensor dimensions
    int M = A.size(0);
    int K_A = A.size(1);
    int N = B.size(0);
    int K_B = B.size(1);

    // Validate dimensions match specification (N=4096, K=4096)
    if (N != 4096) {
        throw std::runtime_error("B dimension N must be 4096, got " + std::to_string(N));
    }
    if (K_A != 4096) {
        throw std::runtime_error("A dimension K must be 4096, got " + std::to_string(K_A));
    }
    if (K_B != 4096) {
        throw std::runtime_error("B dimension K must be 4096, got " + std::to_string(K_B));
    }
    if (K_A != K_B) {
        throw std::runtime_error("K dimensions must match: A.K=" + std::to_string(K_A) + ", B.K=" + std::to_string(K_B));
    }

    // Allocate output tensor C [M, N]
    torch::Tensor C = torch::empty({M, N}, A.options());

    // Get raw pointers using at::Half type (PyTorch's half type alias)
    // Cast to __half* since at::Half and __half are binary compatible
    const __half* A_ptr = reinterpret_cast<const __half*>(A.data_ptr<at::Half>());
    const __half* B_ptr = reinterpret_cast<const __half*>(B.data_ptr<at::Half>());
    __half* C_ptr = reinterpret_cast<__half*>(C.data_ptr<at::Half>());

    // Launch CUDA kernel
    launch_gemm_kernel(A_ptr, B_ptr, C_ptr, M, N, K_A);

    // Synchronize to ensure completion
    CUDA_CHECK(cudaDeviceSynchronize());

    return C;
}

// PyTorch extension module binding
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.doc() = "GEMM kernel optimized for A800 GPU";
    m.def("run", &run, "Execute GEMM operation: C = A @ B.T where A is [M, K], B is [N, K], C is [M, N]");
}
